+
+struct WorkStealingWaker {
+    task_id: TaskId,
+    wake_state: Arc<crate::record::task::TaskWakeState>,
+    global: Arc<GlobalQueue>,
+    parker: Parker,
+}
+
+impl WorkStealingWaker {
+    fn schedule(&self) {
+        if self.wake_state.notify() {
+            self.global.push(self.task_id);
+            self.parker.unpark();
+        }
+    }
+}
